@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput" placeholder="Type your notes here..."></textarea>

<div class="d-flex align-items-center gap-2 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted ms-2">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string lastSavedContent = string.Empty;
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;
    private DotNetObjectReference<Notepad>? dotNetRef;

    private const string StorageKey = "notepad-content";

    private bool HasUnsavedChanges => content != lastSavedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/Pages/Notepad.razor.js");

            var saved = await module.InvokeAsync<string?>("load", StorageKey);
            if (!string.IsNullOrEmpty(saved))
            {
                content = saved;
                lastSavedContent = saved;
                StateHasChanged();
            }

            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("registerBeforeUnload", dotNetRef);

            autoSaveTimer = new System.Threading.Timer(async _ =>
            {
                if (HasUnsavedChanges)
                {
                    await InvokeAsync(SaveNow);
                }
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    [JSInvokable]
    public bool GetHasUnsavedChanges() => HasUnsavedChanges;

    private async Task SaveNow()
    {
        if (module is null) return;

        await module.InvokeVoidAsync("save", StorageKey, content);
        lastSavedContent = content;
        lastSavedAt = DateTime.Now;
        StateHasChanged();
    }

    private async Task Clear()
    {
        if (module is null) return;

        content = string.Empty;
        lastSavedContent = string.Empty;
        lastSavedAt = null;
        await module.InvokeVoidAsync("remove", StorageKey);
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }

        if (module is not null)
        {
            await module.InvokeVoidAsync("unregisterBeforeUnload");
            await module.DisposeAsync();
        }

        dotNetRef?.Dispose();
    }
}

let beforeUnloadHandler = null;

export function save(key, value) {
    localStorage.setItem(key, value);
}

export function load(key) {
    return localStorage.getItem(key);
}

export function remove(key) {
    localStorage.removeItem(key);
}

export function registerBeforeUnload(dotNetRef) {
    beforeUnloadHandler = (e) => {
        const hasChanges = dotNetRef.invokeMethod("GetHasUnsavedChanges");
        if (hasChanges) {
            e.preventDefault();
        }
    };
    window.addEventListener("beforeunload", beforeUnloadHandler);
}

export function unregisterBeforeUnload() {
    if (beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

